/** Sparkline corto para las tarjetas: últimos n valores de la serie. */
export function sparkFrom(h: SeriePunto[] | undefined, n = 24): number[] {
  if (!h || !h.length) return [];
  return h.slice(-n).map((p) => p.v);
}
